Docs.example:
This sample shows how to call Create.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
Indexes client = new AIProjectClient(endpoint, credential).GetIndexesClient(apiVersion: "2025-05-01-preview");

Index body = new AzureAISearchIndex("<connectionName>", "<indexName>");
Response<Index> response = client.Create("<name>", body);

This sample shows how to call Create with all parameters.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
Indexes client = new AIProjectClient(endpoint, credential).GetIndexesClient(apiVersion: "2025-05-01-preview");

Index body = new AzureAISearchIndex("<connectionName>", "<indexName>")
{
    Stage = "<stage>",
    Description = "<description>",
    Tags =
    {
        ["key"] = "<tags>"
    },
};
Response<Index> response = client.Create("<name>", body);

This sample shows how to call Create and parse the result.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
Indexes client = new AIProjectClient(endpoint, credential).GetIndexesClient(apiVersion: "2025-05-01-preview");

using RequestContent content = RequestContent.Create(new
{
    type = "AzureSearch",
    connectionName = "<connectionName>",
    indexName = "<indexName>",
});
Response response = client.Create("<name>", content);

JsonElement result = JsonDocument.Parse(response.ContentStream).RootElement;
Console.WriteLine(result.GetProperty("type").ToString());
Console.WriteLine(result.GetProperty("name").ToString());
Console.WriteLine(result.GetProperty("version").ToString());

This sample shows how to call Create with all parameters and request content and parse the result.

Uri endpoint = new Uri("<endpoint>");
AzureKeyCredential credential = new AzureKeyCredential("<key>");
Indexes client = new AIProjectClient(endpoint, credential).GetIndexesClient(apiVersion: "2025-05-01-preview");

using RequestContent content = RequestContent.Create(new
{
    type = "AzureSearch",
    connectionName = "<connectionName>",
    indexName = "<indexName>",
    stage = "<stage>",
    description = "<description>",
    tags = new
    {
        key = "<tags>",
    },
});
Response response = client.Create("<name>", content);

JsonElement result = JsonDocument.Parse(response.ContentStream).RootElement;
Console.WriteLine(result.GetProperty("type").ToString());
Console.WriteLine(result.GetProperty("stage").ToString());
Console.WriteLine(result.GetProperty("id").ToString());
Console.WriteLine(result.GetProperty("name").ToString());
Console.WriteLine(result.GetProperty("version").ToString());
Console.WriteLine(result.GetProperty("description").ToString());
Console.WriteLine(result.GetProperty("tags").GetProperty("<key>").ToString());

